class Solution {
    public int nQueensIi(int n) {
        return solveNQueens(n, 0, new boolean[n], new boolean[2 * n], new boolean[2 * n]);
    }
    private int solveNQueens(int n, int row, boolean[] cols, boolean[] diag1, boolean[] diag2) {
        if (row == n) {
            return 1;
        }
        int count = 0;
        for (int col = 0; col < n; col++) {
            if (!cols[col] && !diag1[row + col] && !diag2[row - col + n - 1]) {
                cols[col] = true;
                diag1[row + col] = true;
                diag2[row - col + n - 1] = true;
                count += solveNQueens(n, row + 1, cols, diag1, diag2);
                cols[col] = false;
                diag1[row + col] = false;
                diag2[row - col + n - 1] = false;
            }
        }
        return count;
    }
}

