func solveNQueens(n int, row int, cols int, diag1 int, diag2 int) int {
    if row == n {
        return 1
    }
    count := 0
    for col := 0; col < n; col++ {
        if (cols&(1<<col)) == 0 && (diag1&(1<<(row+col))) == 0 && (diag2&(1<<(row-col+n-1))) == 0 {
            count += solveNQueens(n, row+1, cols|(1<<col), diag1|(1<<(row+col)), diag2|(1<<(row-col+n-1)))
        }
    }
    return count
}

