package main

func nQueensIi(data int) int {
    cols := make([]bool, data)
    diag1 := make([]bool, 2*data)
    diag2 := make([]bool, 2*data)
    return backtrack(0, data, &cols, &diag1, &diag2)
}

func backtrack(row, n int, cols, diag1, diag2 *[]bool) int {
    if row == n {
        return 1
    }
    count := 0
    for col := 0; col < n; col++ {
        if !(*cols)[col] && !(*diag1)[row+col] && !(*diag2)[row-col+n-1] {
            (*cols)[col] = true
            (*diag1)[row+col] = true
            (*diag2)[row-col+n-1] = true
            count += backtrack(row+1, n, cols, diag1, diag2)
            (*cols)[col] = false
            (*diag1)[row+col] = false
            (*diag2)[row-col+n-1] = false
        }
    }
    return count
}

